// client/lib/migrate.ts
import { z } from 'zod';
export function withMigration<V1, V2>(currentVersion: number, migrations: Record<number, (old: any) => any>) {
  return (raw: { version: number; data: any }): { version: number; data: V2 } => {
    let data = raw.data;
    for (let v = raw.version; v < currentVersion; v++) data = migrations[v + 1](data);
    return { version: currentVersion, data };
  };
}

